class ReservaTests(BaseTestCase):
    """Tests para creaciÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³n y cancelaciÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³n de reservas."""

    def test_crear_reserva_sin_login_redirige(self):
        """Intentar crear reserva sin sesiÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³n redirige a login."""
        response = self.client.get(reverse('crear_reserva'))
        self.assertRedirects(response, reverse('login'))

    def test_crear_reserva_exitosa(self):
        """Crear reserva vÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡lida funciona y redirige a mis reservas."""
        self.login_como(self.usuario)
        fecha_manana = date.today() + timedelta(days=1)
        response = self.client.post(reverse('crear_reserva'), {
            'cancha': self.cancha.id,
            'fecha': fecha_manana.isoformat(),
            'hora_inicio': '14:00',
            'hora_fin': '15:00',
            'lista_invitados': 'Pedro, Luis, Ana',
            'observacion': 'Traer balÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³n',
        })
        self.assertEqual(response.status_code, 302)
        self.assertTrue(
            Reserva.objects.filter(
                usuario=self.usuario,
                cancha=self.cancha,
                fecha=fecha_manana,
            ).exists()
        )
        reserva = Reserva.objects.get(
            usuario=self.usuario,
            cancha=self.cancha,
            fecha=fecha_manana,
        )
        self.assertTrue(reserva.codigo_qr.startswith('ACC-'))

    def test_crear_reserva_duplicada_falla(self):
        """No se puede crear reserva en franja ya ocupada."""
        self.login_como(self.usuario)
        fecha_manana = date.today() + timedelta(days=1)

        # Crear primera reserva
        Reserva.objects.create(
            usuario=self.usuario,
            cancha=self.cancha,
            fecha=fecha_manana,
            hora_inicio=time(14, 0),
            hora_fin=time(15, 0),
            estado='confirmada',
            codigo_qr='test-qr-unique-1',
            lista_invitados='Juan',
        )

        # Intentar crear duplicada
        response = self.client.post(reverse('crear_reserva'), {
            'cancha': self.cancha.id,
            'fecha': fecha_manana.isoformat(),
            'hora_inicio': '14:00',
            'hora_fin': '15:00',
            'lista_invitados': 'Otro grupo',
        })
        # DeberÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â­a mostrar error (no crear segunda reserva)
        count = Reserva.objects.filter(
            cancha=self.cancha,
            fecha=fecha_manana,
            hora_inicio=time(14, 0),
            estado='confirmada',
        ).count()
        self.assertEqual(count, 1)

    def test_cancelar_reserva(self):
        """Cancelar reserva confirmada la marca como cancelada."""
        self.login_como(self.usuario)
        fecha_manana = date.today() + timedelta(days=1)
        reserva = Reserva.objects.create(
            usuario=self.usuario,
            cancha=self.cancha,
            fecha=fecha_manana,
            hora_inicio=time(14, 0),
            hora_fin=time(15, 0),
            estado='confirmada',
            codigo_qr='test-cancel-qr',
            lista_invitados='Test',
        )
        response = self.client.get(reverse('cancelar_reserva', args=[reserva.id]))
        reserva.refresh_from_db()
        self.assertEqual(reserva.estado, 'cancelada')

    def test_cancelar_reserva_ajena_falla(self):
        """No se puede cancelar la reserva de otro usuario."""
        self.login_como(self.usuario)
        fecha_manana = date.today() + timedelta(days=1)
        reserva_ajena = Reserva.objects.create(
            usuario=self.recepcionista,
            cancha=self.cancha,
            fecha=fecha_manana,
            hora_inicio=time(14, 0),
            hora_fin=time(15, 0),
            estado='confirmada',
            codigo_qr='test-ajena-qr',
            lista_invitados='Test',
        )
        response = self.client.get(reverse('cancelar_reserva', args=[reserva_ajena.id]))
        self.assertEqual(response.status_code, 404)

    def test_mis_reservas_solo_propias(self):
        """Un usuario solo ve sus propias reservas."""
        self.login_como(self.usuario)
        Reserva.objects.create(
            usuario=self.usuario,
            cancha=self.cancha,
            fecha=date.today() + timedelta(days=1),
            hora_inicio=time(14, 0),
            hora_fin=time(15, 0),
            estado='confirmada',
            codigo_qr='test-mis-1',
            lista_invitados='Test',
        )
        Reserva.objects.create(
            usuario=self.recepcionista,
            cancha=self.cancha,
            fecha=date.today() + timedelta(days=2),
            hora_inicio=time(14, 0),
            hora_fin=time(15, 0),
            estado='confirmada',
            codigo_qr='test-mis-2',
            lista_invitados='Test',
        )
        response = self.client.get(reverse('mis_reservas'))
        self.assertEqual(response.status_code, 200)
        reservas_en_pagina = response.context['reservas']
        ids = [r.usuario_id for r in reservas_en_pagina]
        self.assertTrue(all(uid == self.usuario.id for uid in ids))

    def test_reserva_recepcion_form_usa_selector_de_horarios(self):
        """Recepcion debe escoger una franja configurada, no escribir horas libres."""
        form = ReservaRecepcionForm(data={
            'cancha': self.cancha.id,
            'fecha': (date.today() + timedelta(days=1)).isoformat(),
        })

        self.assertIn('id_horario_disponible', form.as_p())
        self.assertFalse(form.fields['hora_inicio'].required)
        self.assertFalse(form.fields['hora_fin'].required)
        self.assertNotIn('readonly', form.fields['cancha'].widget.attrs)
        self.assertNotIn('style', form.fields['cancha'].widget.attrs)

    def test_recepcionista_puede_crear_reserva_manual_con_franja_configurada(self):
        """Recepcion puede crear una reserva manual usando una franja existente."""
        self.login_como(self.recepcionista)
        fecha_manana = date.today() + timedelta(days=1)

        response = self.client.post(reverse('crear_reserva_recepcion'), {
            'usuario': self.usuario.id,
            'cancha': self.cancha.id,
            'fecha': fecha_manana.isoformat(),
            'horario_disponible': '14:00|15:00',
            'cantidad_invitados': '2',
            'invitado_1': 'Pedro',
            'invitado_2': 'Luis',
            'observacion': 'Reserva hecha en mostrador',
        })

        self.assertEqual(response.status_code, 302)
        self.assertRedirects(response, reverse('calendario_reservas'))
        reserva = Reserva.objects.get(usuario=self.usuario, cancha=self.cancha, fecha=fecha_manana)
        self.assertEqual(reserva.estado, 'confirmada')
        self.assertEqual(reserva.hora_inicio, time(14, 0))
        self.assertEqual(reserva.hora_fin, time(15, 0))
        self.assertEqual(reserva.invitados_lista, ['Pedro', 'Luis'])
        self.assertTrue(reserva.codigo_qr.startswith('ACC-'))

    def test_reserva_recepcion_form_normaliza_campos_dinamicos_de_invitados(self):
        """El formulario reconstruye la lista desde los campos dinamicos de acompanantes."""
        fecha_manana = date.today() + timedelta(days=1)

        form = ReservaRecepcionForm(data={
            'usuario': self.usuario.id,
            'cancha': self.cancha.id,
            'fecha': fecha_manana.isoformat(),
            'horario_disponible': '14:00|15:00',
            'cantidad_invitados': '2',
            'invitado_1': ' Pedro  ',
            'invitado_2': 'Maria Lopez',
            'observacion': '',
        })

        self.assertTrue(form.is_valid(), form.errors)
        self.assertEqual(form.cleaned_data['lista_invitados'], 'Pedro\nMaria Lopez')

    def test_horarios_disponibles_recepcion_devuelve_franjas_configuradas(self):
        """Recepcion consulta solo las franjas activas y libres de una cancha."""
        self.login_como(self.recepcionista)
        fecha_manana = date.today() + timedelta(days=1)

        response = self.client.get(reverse('recepcion_horarios_disponibles'), {
            'cancha': self.cancha.id,
            'fecha': fecha_manana.isoformat(),
        })

        self.assertEqual(response.status_code, 200)
        data = response.json()
