class QRPuntosTests(BaseTestCase):
    """Tests para validaciÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³n de QR y sistema de puntos."""

    def setUp(self):
        super().setUp()
        self.reserva = Reserva.objects.create(
            usuario=self.usuario,
            cancha=self.cancha,
            fecha=date.today(),
            hora_inicio=time(10, 0),
            hora_fin=time(11, 0),
            estado='confirmada',
            codigo_qr='qr-test-001',
            lista_invitados='Pedro',
        )

    def test_validar_qr_exitoso(self):
        """Validar QR marca como asistida y otorga puntos."""
        self.login_como(self.recepcionista)
        puntos_antes = self.usuario.puntos_acumulados

        response = self.client.post(reverse('validar_qr'), {
            'codigo_qr': 'qr-test-001',
        })
        self.assertEqual(response.status_code, 200)

        # Reserva marcada como asistida
        self.reserva.refresh_from_db()
        self.assertEqual(self.reserva.estado, 'asistida')

        # Puntos otorgados
        self.usuario.refresh_from_db()
        config = ConfiguracionPuntos.obtener()
        self.assertEqual(
            self.usuario.puntos_acumulados,
            puntos_antes + config.puntos_por_asistencia
        )

        # Historial de puntos creado
        self.assertTrue(
            PuntosHistorial.objects.filter(
                usuario=self.usuario,
                reserva=self.reserva,
                tipo_movimiento='otorgado',
            ).exists()
        )
        self.assertContains(response, 'Pedro')
        self.assertContains(response, 'Ingreso marcado como visto')

    def test_validar_qr_inexistente(self):
        """Validar QR inexistente muestra error."""
        self.login_como(self.recepcionista)
        response = self.client.post(reverse('validar_qr'), {
            'codigo_qr': 'qr-no-existe',
        })
        self.assertEqual(response.status_code, 200)
        resultado = response.context['resultado']
        self.assertFalse(resultado['valido'])

    def test_validar_qr_ya_asistida(self):
        """No se puede validar una reserva ya asistida."""
        self.login_como(self.recepcionista)
        self.reserva.estado = 'asistida'
        self.reserva.save()

        response = self.client.post(reverse('validar_qr'), {
            'codigo_qr': 'qr-test-001',
        })
        resultado = response.context['resultado']
        self.assertFalse(resultado['valido'])

    def test_usuario_no_puede_validar_qr(self):
        """Un usuario normal no puede acceder a validar QR."""
        self.login_como(self.usuario)
        response = self.client.get(reverse('validar_qr'))
        self.assertEqual(response.status_code, 403)

    def test_validar_qr_carga_javascript_sin_escapes_invalidos(self):
        """La vista no debe renderizar template literals rotos en JavaScript."""
        self.login_como(self.recepcionista)
        response = self.client.get(reverse('validar_qr'))
        self.assertEqual(response.status_code, 200)
        contenido = response.content.decode('utf-8')
        self.assertIn('placeholder.innerHTML = `', contenido)
        self.assertNotIn('placeholder.innerHTML = \\`', contenido)

    def test_validar_voucher_exitoso(self):
        """El modulo principal valida vouchers y los marca como entregados."""
        canje = CanjeProducto.objects.create(
            usuario=self.usuario,
            producto=self.producto_bar,
            puntos_usados=self.producto_bar.puntos_requeridos,
            codigo='VCH-ABC123',
            estado='pendiente',
        )

        self.login_como(self.recepcionista)
        response = self.client.post(reverse('validar_qr'), {
            'codigo_qr': canje.codigo,
        })

        self.assertEqual(response.status_code, 200)
        canje.refresh_from_db()
        self.assertEqual(canje.estado, 'entregado')
        resultado = response.context['resultado']
        self.assertTrue(resultado['valido'])
        self.assertTrue(resultado['es_voucher'])
        contenido = response.content.decode('utf-8')
        self.assertIn('Abrir PDF', contenido)

    def test_ticket_voucher_usa_formato_termico(self):
        """El ticket del voucher debe generarse como PDF compacto."""
        canje = CanjeProducto.objects.create(
            usuario=self.usuario,
            producto=self.producto_bar,
            puntos_usados=self.producto_bar.puntos_requeridos,
            codigo='VCH-TICKET1',
            estado='entregado',
        )

        self.login_como(self.recepcionista)
        response = self.client.get(reverse('ticket_voucher', args=[canje.id]))

        self.assertEqual(response.status_code, 200)
        self.assertEqual(response['Content-Type'], 'application/pdf')
        self.assertIn('inline; filename="ticket_voucher_VCH-TICKET1.pdf"', response['Content-Disposition'])
        self.assertTrue(response.content.startswith(b'%PDF'))

    def test_generar_voucher_qr_para_dueno(self):
        """El usuario dueno puede abrir la imagen QR de su voucher."""
        canje = CanjeProducto.objects.create(
            usuario=self.usuario,
            producto=self.producto_bar,
            puntos_usados=50,
            codigo='VCH-QR001',
        )

        self.login_como(self.usuario)
        response = self.client.get(reverse('generar_voucher_qr', args=[canje.codigo]))

        self.assertEqual(response.status_code, 200)
        self.assertEqual(response['Content-Type'], 'image/png')

    def test_validar_codigo_legacy_sin_prefijo_sigue_funcionando(self):
        """Los codigos antiguos sin ACC-/VCH- siguen siendo validos."""
        reserva_legacy = Reserva.objects.create(
            usuario=self.usuario,
            cancha=self.cancha,
            fecha=date.today() + timedelta(days=1),
            hora_inicio=time(14, 0),
            hora_fin=time(15, 0),
            estado='confirmada',
            codigo_qr='legacy-qr-001',
            lista_invitados='Pedro',
        )

        self.login_como(self.recepcionista)
        response = self.client.post(reverse('validar_qr'), {
            'codigo_qr': reserva_legacy.codigo_qr,
        })

        self.assertEqual(response.status_code, 200)
        reserva_legacy.refresh_from_db()
        self.assertEqual(reserva_legacy.estado, 'asistida')


