class CanjePuntosTests(BaseTestCase):
    """Tests para el canje de puntos."""

    def test_canjear_puntos_page_loads(self):
        """El catalogo de canjes carga correctamente."""
        self.login_como(self.usuario)
        response = self.client.get(reverse('canjear_puntos'))
        self.assertEqual(response.status_code, 200)
        self.assertIn('catalogo', response.context)

    def test_canjear_producto_exitoso(self):
        """Canjear un producto descuenta puntos y crea voucher."""
        self.usuario.puntos_acumulados = 100
        self.usuario.save()
        self.login_como(self.usuario)

        response = self.client.post(reverse('canjear_producto', args=[self.producto_bar.id]))
        self.assertEqual(response.status_code, 302)
        self.assertRedirects(response, reverse('canjear_puntos'))

        self.usuario.refresh_from_db()
        self.producto_bar.refresh_from_db()
        self.assertEqual(self.usuario.puntos_acumulados, 50)
        self.assertEqual(self.producto_bar.stock, 4)
        canje = CanjeProducto.objects.get(usuario=self.usuario, producto=self.producto_bar)
        self.assertEqual(canje.puntos_usados, 50)
        self.assertTrue(canje.codigo.startswith('VCH-'))
        self.assertTrue(
            PuntosHistorial.objects.filter(
                usuario=self.usuario,
                tipo_movimiento='canjeado',
                puntos=self.producto_bar.puntos_requeridos,
            ).exists()
        )

    def test_canjear_producto_con_puntos_insuficientes(self):
        """No se puede canjear un producto si faltan puntos."""
        self.usuario.puntos_acumulados = 20
        self.usuario.save()
        self.login_como(self.usuario)

        response = self.client.post(reverse('canjear_producto', args=[self.producto_bar.id]))
        self.assertEqual(response.status_code, 302)
        self.assertRedirects(response, reverse('canjear_puntos'))
        self.usuario.refresh_from_db()
        self.assertEqual(self.usuario.puntos_acumulados, 20)
        self.assertFalse(
            CanjeProducto.objects.filter(usuario=self.usuario, producto=self.producto_bar).exists()
        )

    def test_canjear_producto_sin_stock_no_crea_voucher(self):
        """No se puede canjear un producto agotado."""
        self.usuario.puntos_acumulados = 100
        self.usuario.save()
        self.producto_bar.stock = 0
        self.producto_bar.save(update_fields=['stock'])
        self.login_como(self.usuario)

        response = self.client.post(reverse('canjear_producto', args=[self.producto_bar.id]))
        self.assertEqual(response.status_code, 302)
        self.assertRedirects(response, reverse('canjear_puntos'))

        self.usuario.refresh_from_db()
        self.producto_bar.refresh_from_db()
        self.assertEqual(self.usuario.puntos_acumulados, 100)
        self.assertEqual(self.producto_bar.stock, 0)
        self.assertFalse(
            CanjeProducto.objects.filter(usuario=self.usuario, producto=self.producto_bar).exists()
        )

    def test_get_en_canjear_producto_redirige_al_catalogo(self):
        """La ruta de canje solo acepta POST."""
        self.login_como(self.usuario)
        response = self.client.get(reverse('canjear_producto', args=[self.producto_bar.id]))
        self.assertEqual(response.status_code, 302)
        self.assertRedirects(response, reverse('canjear_puntos'))

    def test_voucher_entregado_no_aparece_como_activo(self):
        """Un voucher ya entregado no debe mostrarse como voucher activo."""
        canje = CanjeProducto.objects.create(
            usuario=self.usuario,
            producto=self.producto_bar,
            puntos_usados=50,
            codigo='VCH-USED01',
            estado=CanjeProducto.Estado.ENTREGADO,
        )

        self.login_como(self.usuario)
        response = self.client.get(reverse('canjear_puntos'))

        self.assertIsNone(response.context['canje_activo'])
        self.assertContains(response, canje.codigo)
        self.assertContains(response, 'Canjeado')

    def test_voucher_caducado_muestra_estado_correcto(self):
        """Un voucher pendiente pero vencido debe mostrarse como caducado."""
        canje = CanjeProducto.objects.create(
            usuario=self.usuario,
            producto=self.producto_bar,
            puntos_usados=50,
            codigo='VCH-OLD001',
        )
        canje.fecha = timezone.now() - timedelta(days=31)
        canje.save(update_fields=['fecha'])

        self.assertFalse(canje.esta_vigente)
        self.assertEqual(canje.estado_visual, 'caducado')
        self.assertEqual(canje.estado_visual_label, 'Caducado')


