class CanchaAdminTests(BaseTestCase):
    """Tests para la gestion administrativa de canchas."""

    def test_admin_puede_crear_cancha_con_capacidad(self):
        self.login_como(self.admin)
        response = self.client.post(reverse('admin_canchas'), {
            'nombre': 'Cancha Nueva',
            'tipo_deporte': 'futbol',
            'ubicacion': 'Zona Norte',
            'capacidad_jugadores_min': 11,
            'capacidad_jugadores_max': 20,
            'estado': 'disponible',
            'descripcion': 'Cancha reglamentaria',
            'tipo_personalizado': '',
        })
        self.assertRedirects(response, reverse('admin_canchas'))
        cancha = Cancha.objects.get(nombre='Cancha Nueva')
        self.assertEqual(cancha.capacidad_jugadores_min, 11)
        self.assertEqual(cancha.capacidad_jugadores_max, 20)
        self.assertEqual(cancha.tipo_personalizado, '')

    def test_admin_debe_indicar_tipo_personalizado_cuando_es_otro(self):
        self.login_como(self.admin)
        response = self.client.post(reverse('admin_canchas'), {
            'nombre': 'Espacio Nuevo',
            'tipo_deporte': 'otro',
            'ubicacion': 'Zona Sur',
            'capacidad_jugadores_min': 2,
            'capacidad_jugadores_max': 8,
            'estado': 'disponible',
            'descripcion': 'Espacio especial',
            'tipo_personalizado': '',
        })
        self.assertEqual(response.status_code, 200)
        self.assertContains(response, 'Escribe el nombre del espacio personalizado.')

    def test_admin_puede_crear_espacio_personalizado(self):
        self.login_como(self.admin)
        response = self.client.post(reverse('admin_canchas'), {
            'nombre': 'Piscina Central',
            'tipo_deporte': 'otro',
            'tipo_personalizado': 'Piscina',
            'ubicacion': 'Area humeda',
            'capacidad_jugadores_min': 1,
            'capacidad_jugadores_max': 12,
            'estado': 'disponible',
            'descripcion': 'Piscina semiolimpica',
        })
        self.assertRedirects(response, reverse('admin_canchas'))
        cancha = Cancha.objects.get(nombre='Piscina Central')
        self.assertEqual(cancha.tipo_personalizado, 'Piscina')
        self.assertEqual(cancha.tipo_deporte_label, 'Piscina')


class CanchasTests(BaseTestCase):
    """Tests para las vistas de canchas y disponibilidad."""

    def test_lista_canchas(self):
        """Lista de canchas carga y muestra las canchas."""
        self.login_como(self.usuario)
        response = self.client.get(reverse('lista_canchas'))
        self.assertEqual(response.status_code, 200)
        self.assertIn('canchas', response.context)

    def test_filtrar_canchas_por_tipo(self):
        """Filtrar canchas por tipo de deporte funciona."""
        self.login_como(self.usuario)
        response = self.client.get(reverse('lista_canchas'), {'tipo': 'futbol'})
        self.assertEqual(response.status_code, 200)
        for cancha in response.context['canchas']:
            self.assertEqual(cancha.tipo_deporte, 'futbol')

    def test_disponibilidad_con_cancha_y_fecha(self):
        """Consulta de disponibilidad con cancha y fecha muestra horarios."""
        self.login_como(self.usuario)
        fecha_manana = (date.today() + timedelta(days=1)).isoformat()
        response = self.client.get(reverse('disponibilidad'), {
            'cancha': self.cancha.id,
            'fecha': fecha_manana,
        })
        self.assertEqual(response.status_code, 200)

class ReportesDashboardTests(BaseTestCase):
    """Tests del dashboard y exportaciones de reportes."""

    def test_reportes_no_muestra_puntos_recientes(self):
        """El dashboard ya no muestra la tabla de puntos recientes."""
        self.login_como(self.admin)
        response = self.client.get(reverse('reportes'))
        self.assertEqual(response.status_code, 200)
        self.assertNotContains(response, 'Puntos recientes')

    def test_exportar_pdf_como_admin(self):
        """Admin puede exportar reportes a PDF."""
        self.login_como(self.admin)
        response = self.client.get(reverse('exportar_pdf'))
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response['Content-Type'], 'application/pdf')

    def test_exportar_excel_como_admin(self):
        """Admin puede exportar reportes a Excel sin hoja de puntos."""
        reservas = [
            Reserva(
                usuario=self.usuario,
                cancha=self.cancha,
                fecha=date.today() + timedelta(days=index),
                hora_inicio=time(10, 0),
                hora_fin=time(11, 0),
                estado='confirmada',
                lista_invitados='Invitado A, Invitado B',
            )
            for index in range(20)
        ]
        Reserva.objects.bulk_create(reservas)

        self.login_como(self.admin)
        response = self.client.get(reverse('exportar_excel'))
        self.assertEqual(response.status_code, 200)
        self.assertIn('spreadsheetml', response['Content-Type'])

        workbook = load_workbook(BytesIO(response.content))
        self.assertEqual(
            workbook.sheetnames,
            ['Resumen', 'Reservas', 'Usuarios', 'Canchas', 'Tendencias']
        )
        self.assertNotIn('Puntos', workbook.sheetnames)
        self.assertEqual(workbook['Reservas']['A4'].value, 'ID')

    def test_usuario_no_puede_exportar_pdf(self):
        """Usuario normal no puede exportar PDF."""
        self.login_como(self.usuario)
        response = self.client.get(reverse('exportar_pdf'))
        self.assertEqual(response.status_code, 403)

    def test_municipio_puede_exportar(self):
        """Municipio puede exportar reportes."""
        self.login_como(self.municipio)
        response = self.client.get(reverse('exportar_excel'))
        self.assertEqual(response.status_code, 200)

